import{_ as t,a,b as l,c as n,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as r,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"افزودن Telegram Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/telegram.md","filePath":"fa/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"fa/upload/telegram.md"};function h(p,e,m,b,g,u){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="افزودن-telegram-channel" tabindex="-1">افزودن Telegram Channel <a class="header-anchor" href="#افزودن-telegram-channel" aria-label="Permalink to &quot;افزودن Telegram Channel&quot;">​</a></h1><h2 id="پیش-از-شروع-چه-چیزهایی-لازم-است" tabindex="-1">پیش از شروع چه چیزهایی لازم است <a class="header-anchor" href="#پیش-از-شروع-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;پیش از شروع چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>کاربرد</th></tr></thead><tbody><tr><td>Telegram account</td><td>برای ساخت bot و storage channel</td></tr><tr><td><code>@BotFather</code></td><td>برای ساخت Telegram bot</td></tr><tr><td>Telegram channel</td><td>مقصد نهایی ذخیره files</td></tr><tr><td><code>@userinfobot</code></td><td>برای پیدا کردن <code>Chat ID</code> channel</td></tr></tbody></table><h2 id="کجا-اضافه-کنیم" tabindex="-1">کجا اضافه کنیم <a class="header-anchor" href="#کجا-اضافه-کنیم" aria-label="Permalink to &quot;کجا اضافه کنیم&quot;">​</a></h2><ol><li>System Settings را باز کنید.</li><li>وارد Upload Settings شوید.</li><li>از گوشه بالا سمت راست Add Channel را بزنید.</li><li><code>Telegram</code> را انتخاب کنید.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کاربرد</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص برای این channel، مثل <code>Telegram Primary</code>.</td><td>Required</td></tr><tr><td>Active</td><td>این channel را enable یا disable می‌کند.</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>token مربوط به Telegram bot.</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>ID مربوط به Telegram channel.</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>فقط وقتی Telegram access ناپایدار است استفاده کنید. URL کامل را همراه <code>https://</code> وارد کنید.</td><td>Optional</td></tr><tr><td>Remark</td><td>یادداشت برای نگهداری بعدی.</td><td>Optional</td></tr></tbody></table><h2 id="مراحل-راه‌اندازی" tabindex="-1">مراحل راه‌اندازی <a class="header-anchor" href="#مراحل-راه‌اندازی" aria-label="Permalink to &quot;مراحل راه‌اندازی&quot;">​</a></h2><h3 id="_1-ساخت-telegram-bot" tabindex="-1">1. ساخت Telegram Bot <a class="header-anchor" href="#_1-ساخت-telegram-bot" aria-label="Permalink to &quot;1. ساخت Telegram Bot&quot;">​</a></h3><ol><li>Telegram را باز کنید و <code>@BotFather</code> را جست‌وجو کنید.</li><li>chat را باز کنید و <code>Start</code> را بزنید.</li><li><code>/newbot</code> را ارسال کنید.</li><li>طبق پیام‌ها، bot display name را وارد کنید.</li><li>bot username را وارد کنید. معمولاً username باید با <code>bot</code> تمام شود.</li><li>پس از ساخت bot، <code>@BotFather</code> یک bot token برمی‌گرداند.</li></ol><p>این همان مقداری است که باید در ImgBed داخل <code>Bot Token</code> وارد شود.</p><p><img src="'+t+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-ساخت-channel" tabindex="-1">2. ساخت Channel <a class="header-anchor" href="#_2-ساخت-channel" aria-label="Permalink to &quot;2. ساخت Channel&quot;">​</a></h3><ol><li>در Telegram روی New Channel بزنید.</li><li>channel name را وارد کنید.</li><li>ساخت channel را کامل کنید.</li></ol><p>هم public channel و هم private channel قابل استفاده است.</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-افزودن-bot-به-channel" tabindex="-1">3. افزودن Bot به Channel <a class="header-anchor" href="#_3-افزودن-bot-به-channel" aria-label="Permalink to &quot;3. افزودن Bot به Channel&quot;">​</a></h3><ol><li>channel ساخته‌شده را باز کنید.</li><li>channel settings را باز کنید.</li><li>بخش افزودن member یا administrator را باز کنید.</li><li>bot username ساخته‌شده را جست‌وجو کنید.</li><li>bot را به channel اضافه کنید.</li></ol><p>برای upload قابل‌اعتمادتر، بهتر است به bot دسترسی administrator بدهید.</p><p><img src="'+l+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-گرفتن-channel-id-با-user-info-get-id-idbot" tabindex="-1">4. گرفتن Channel ID با User Info - Get ID - IDbot <a class="header-anchor" href="#_4-گرفتن-channel-id-با-user-info-get-id-idbot" aria-label="Permalink to &quot;4. گرفتن Channel ID با User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>در Telegram، <code>@userinfobot</code> را جست‌وجو کنید. نام نمایشی آن معمولاً <code>User Info - Get ID - IDbot</code> است.</li><li>chat را باز کنید و <code>Start</code> را بزنید.</li><li>از گزینه‌های bot، <code>Channel</code> را انتخاب کنید.</li><li>در message picker، target channel را انتخاب و برای <code>@userinfobot</code> ارسال کنید.</li><li>وقتی result برگشت، عددی را که به شکل <code>Id: -100...</code> نمایش داده می‌شود copy کنید.</li></ol><p>عدد شروع‌شونده با <code>-100</code> همان <code>Session ID (Chat ID)</code> موردنیاز ImgBed است.</p><p><img src="'+n+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-پر-کردن-telegram-channel-در-imgbed" tabindex="-1">5. پر کردن Telegram Channel در ImgBed <a class="header-anchor" href="#_5-پر-کردن-telegram-channel-در-imgbed" aria-label="Permalink to &quot;5. پر کردن Telegram Channel در ImgBed&quot;">​</a></h3><p>به channel configuration dialog برگردید و fields را این‌گونه پر کنید:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>نام دلخواه، مثل <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Recommended.</td></tr><tr><td>Bot Token</td><td>token دریافت‌شده از <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>عدد <code>-100...</code> دریافت‌شده از <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (optional)</td><td>فقط در صورت نیاز، مثل <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>یادداشت اختیاری.</td></tr></tbody></table><p>در پایان Save را بزنید.</p><p><img src="'+o+`" alt="Edit the configuration" loading="lazy"></p><h2 id="روش-بررسی" tabindex="-1">روش بررسی <a class="header-anchor" href="#روش-بررسی" aria-label="Permalink to &quot;روش بررسی&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>روش بررسی</th></tr></thead><tbody><tr><td>Channel card appears</td><td>پس از Save، باید card مربوط به Telegram در Upload Settings دیده شود.</td></tr><tr><td>Channel can be enabled</td><td>Active switch باید روشن بماند.</td></tr><tr><td>Configuration is saved</td><td>در detail view باید Bot Token و Chat ID ذخیره‌شده دیده شوند.</td></tr><tr><td>Upload works</td><td>یک test image upload کنید و بررسی کنید در target Telegram channel ظاهر شود.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>با @BotFather یک bot بسازید</span></span>
<span class="line"><span>-&gt; Bot Token را ذخیره کنید</span></span>
<span class="line"><span>-&gt; Telegram channel بسازید</span></span>
<span class="line"><span>-&gt; bot را به channel اضافه کنید و administrator permissions بدهید</span></span>
<span class="line"><span>-&gt; @userinfobot را پیدا کنید و Channel را انتخاب کنید</span></span>
<span class="line"><span>-&gt; یک message از channel به @userinfobot بفرستید</span></span>
<span class="line"><span>-&gt; Id: -100... برگشتی را copy کنید</span></span>
<span class="line"><span>-&gt; Bot Token و Chat ID را در ImgBed وارد کنید</span></span>
<span class="line"><span>-&gt; Save کنید و test image upload کنید</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=d(c,[["render",h]]);export{k as __pageData,T as default};
